+// =============================================================================
+// Q3_K Dequantization → BF16
+// =============================================================================
+// Q3_K block: 256 values packed in 110 bytes (3.44 bits per weight)
+// Layout: [hmask: 32 bytes] [qs: 64 bytes] [scales: 12 bytes] [d: 2 bytes]
+// - hmask: High bit for each of 256 values (1 bit per value)
+// - qs: Low 2 bits for each of 256 values (2 bits per value, 4 per byte)
+// - scales: 8 groups × 6-bit scales packed in 12 bytes
+// - d: Global scale factor (fp16)
+
+constant uint Q3K_BLOCK_SIZE = 110;
+constant uint Q3K_VALUES_PER_BLOCK = 256;
+constant uint Q3K_GROUPS = 8;
+constant uint Q3K_GROUP_SIZE = 32;
+
+kernel void dequantize_q3k_bf16(
+    device const uchar* src_bytes [[buffer(0)]],
+    device bfloat16_t* dst        [[buffer(1)]],
+    constant uint& num_blocks     [[buffer(2)]],
+    uint gid                      [[thread_position_in_grid]]
+) {
+    if (gid >= num_blocks) return;
+
+    uint src_offset = gid * Q3K_BLOCK_SIZE;
