+    pub fn preloadVIPExpertsQ4K(self: *Self, tensor_lookup: anytype, n_layers: u32, vip_layers: u32) !void {
+        if (self.mmap_base_ptr == null) {
+            log.err("Cannot preload VIP experts: mmap not initialized", .{});
