+                const gate_name = std.fmt.bufPrint(&buf, "blk.{d}.ffn_gate.{d}.weight", .{ layer_idx, expert_idx }) catch continue;
+                if (tensor_lookup.getTensorOffsetAndSize(gate_name)) |info| {
+                    _ = self.getOrCreateTensorBuffer(gate_name, info.offset, info.size) catch continue;
+                    total_bytes += info.size;
+                    loaded += 1;
+                }
+
+                // Preload up
+                const up_name = std.fmt.bufPrint(&buf, "blk.{d}.ffn_up.{d}.weight", .{ layer_idx, expert_idx }) catch continue;
+                if (tensor_lookup.getTensorOffsetAndSize(up_name)) |info| {
+                    _ = self.getOrCreateTensorBuffer(up_name, info.offset, info.size) catch continue;
