+                    loaded += 1;
+                }
+
+                // Preload down
+                const down_name = std.fmt.bufPrint(&buf, "blk.{d}.ffn_down.{d}.weight", .{ layer_idx, expert_idx }) catch continue;
+                if (tensor_lookup.getTensorOffsetAndSize(down_name)) |info| {
+                    _ = self.getOrCreateTensorBuffer(down_name, info.offset, info.size) catch continue;
+                    total_bytes += info.size;
+                    loaded += 1;
+                }
